import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Quote {
  text: string;
  author: string;
  category: string;
}

interface WidgetData {
  quote: Quote;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { quote } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              Quote of the Day
            </Typography>
            <Typography variant="body1" sx={{ color: '#E5E7EB', fontStyle: 'italic', mt: 1 }}>
              "{quote.text}"
            </Typography>
            <Typography variant="body2" sx={{ color: '#9CA3AF', mt: 1 }}>
              - {quote.author}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            <Chip
              label={quote.category}
              sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#FF5722', color: '#FFF' }}
            />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
